x = tf.constant(
  [[1, 2, 3], 
  [101, 102, 103],
  [11, 12, 13]

]
)
new_x = tf.math.reduce_max(
  tf.math.reduce_min(
    tf.boolean_mask(x, tf.range(len(x)) % 2 == 0),
    axis=1
  )
)
print(new_x)

x = tf.constant(
  [[1, 2, 3],
  [101, 102, 103],
  [11, 12, 13]]
)
mins = []
for i in range(len(x)):
   if i % 2 == 0:
     mins.append(tf.math.reduce_min(x[i]))
print(tf.math.reduce_max(mins))
